public class Solution {
    public static String solve(String s, long k) {
        Stack<Character> stack = new Stack<>();

        for (char c : s.toCharArray()) {
            if (c == '*') {
                if (!stack.isEmpty()) {
                    stack.pop();
                }
            } else if (c == '#') {
                Stack<Character> temp = new Stack<>();
                for (char ch : stack) {
                    temp.push(ch);
                }
                while (!temp.isEmpty()) {
                    stack.push(temp.pop());
                }
            } else if (c == '%') {
                Stack<Character> temp = new Stack<>();
                for (char ch : stack) {
                    temp.push(ch);
                }
                while (!temp.isEmpty()) {
                    stack.push(temp.pop());
                }
            } else {
                stack.push(c);
            }
        }

        if (k < 0 || k >= stack.size()) {
            return ".";
        }

        return String.valueOf(stack.get((int) k));
    }
}
